inline bool VerifyXNNQuantParams(::flatbuffers::Verifier &verifier, const void *obj, XNNQuantParams type) {
  switch (type) {
    case XNNQuantParams::NONE: {
      return true;
    }
    case XNNQuantParams::PerChannelQuant: {
      auto ptr = reinterpret_cast<const fb_xnnpack::PerChannelQuant *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case XNNQuantParams::PerTensorQuant: {
      auto ptr = reinterpret_cast<const fb_xnnpack::PerTensorQuant *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case XNNQuantParams::PerTokenDynamicQuant: {
      auto ptr = reinterpret_cast<const fb_xnnpack::PerTokenDynamicQuant *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case XNNQuantParams::PerChannelGroupQuant: {
      auto ptr = reinterpret_cast<const fb_xnnpack::PerChannelGroupQuant *>(obj);
      return verifier.VerifyTable(ptr);
    }
    default: return true;
  }
}

inline bool VerifyXNNQuantParamsVector(::flatbuffers::Verifier &verifier, const ::flatbuffers::Vector<::flatbuffers::Offset<void>> *values, const ::flatbuffers::Vector<XNNQuantParams> *types) {
  if (!values || !types) return !values && !types;
  if (values->size() != types->size()) return false;
  for (::flatbuffers::uoffset_t i = 0; i < values->size(); ++i) {
    if (!VerifyXNNQuantParams(
        verifier,  values->Get(i), types->GetEnum<XNNQuantParams>(i))) {
      return false;
    }
  }
  return true;
}

